import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useChat } from '../contexts/ChatContext';
import { useWallet } from '../contexts/WalletContext';
import { 
  MessageSquare, 
  Users, 
  Lock, 
  CheckCircle, 
  XCircle,
  Crown,
  Plus,
  X
} from 'lucide-react';

const Dashboard = () => {
  const { chatRooms, createRoom } = useChat();
  const { walletAddress, ownedNFTs } = useWallet();
  const [showCreateRoom, setShowCreateRoom] = useState(false);
  const [roomForm, setRoomForm] = useState({
    name: '',
    description: '',
    requiredNFT: ''
  });

  const formatAddress = (address) => {
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const handleCreateRoom = (e) => {
    e.preventDefault();
    if (roomForm.name.trim() && roomForm.description.trim()) {
      createRoom({
        ...roomForm,
        createdBy: walletAddress
      });
      setRoomForm({ name: '', description: '', requiredNFT: '' });
      setShowCreateRoom(false);
    }
  };

  const handleInputChange = (field, value) => {
    setRoomForm(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
          <p className="text-gray-600">Welcome back, {formatAddress(walletAddress)}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-primary-100 rounded-lg flex items-center justify-center">
              <MessageSquare className="w-5 h-5 text-primary-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Available Rooms</p>
              <p className="text-2xl font-bold text-gray-900">
                {chatRooms.filter(room => room.hasAccess).length}
              </p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center">
              <Crown className="w-5 h-5 text-green-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Owned NFTs</p>
              <p className="text-2xl font-bold text-gray-900">{ownedNFTs.length}</p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
              <Users className="w-5 h-5 text-blue-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Members</p>
              <p className="text-2xl font-bold text-gray-900">
                {chatRooms.reduce((sum, room) => sum + room.memberCount, 0)}
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">Chat Rooms</h2>
          <div className="flex items-center space-x-4">
            <button
              onClick={() => setShowCreateRoom(true)}
              className="btn-primary flex items-center space-x-2"
            >
              <Plus className="w-4 h-4" />
              <span>Create Room</span>
            </button>
            <div className="flex items-center space-x-2 text-sm text-gray-500">
              <CheckCircle className="w-4 h-4 text-green-500" />
              <span>Access Granted</span>
              <XCircle className="w-4 h-4 text-red-500 ml-4" />
              <span>Access Denied</span>
            </div>
          </div>
        </div>

        <div className="space-y-4">
          {chatRooms.map((room) => (
            <div
              key={room.id}
              className={`p-4 rounded-lg border-2 transition-all duration-200 ${
                room.hasAccess
                  ? 'border-green-200 bg-green-50 hover:bg-green-100'
                  : 'border-red-200 bg-red-50'
              }`}
            >
              <div className="flex items-center justify-between">
                <div className="flex-1">
                  <div className="flex items-center space-x-3 mb-2">
                    <h3 className="font-semibold text-gray-900">{room.name}</h3>
                    {room.hasAccess ? (
                      <CheckCircle className="w-5 h-5 text-green-500" />
                    ) : (
                      <Lock className="w-5 h-5 text-red-500" />
                    )}
                    {room.isActive && (
                      <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
                    )}
                  </div>
                  <p className="text-gray-600 text-sm mb-2">{room.description}</p>
                  <div className="flex items-center space-x-4 text-sm text-gray-500">
                    <span>Required: {room.requiredNFT}</span>
                    <span>•</span>
                    <span>{room.memberCount} members</span>
                  </div>
                </div>

                <div className="ml-4">
                  {room.hasAccess ? (
                    <Link
                      to={`/room/${room.id}`}
                      className="btn-primary"
                    >
                      Enter Room
                    </Link>
                  ) : (
                    <button
                      disabled
                      className="px-4 py-2 bg-gray-200 text-gray-500 rounded-lg cursor-not-allowed"
                    >
                      NFT Required
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="card">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Your NFTs</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {ownedNFTs.map((nft) => (
            <div key={nft.id} className="border border-gray-200 rounded-lg p-4">
              <img
                src={nft.image}
                alt={nft.name}
                className="w-full h-32 object-cover rounded-lg mb-3"
              />
              <h3 className="font-medium text-gray-900">{nft.name}</h3>
              <p className="text-sm text-gray-600">{nft.collection}</p>
              <p className="text-xs text-gray-500">Token ID: {nft.tokenId}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
